mapper.select:
SELECT * FROM t_kpi_sign_record
WHERE 1=1

    AND data_date >= #{startDate}


    AND data_date <= #{endDate}


    AND courier_name LIKE CONCAT('%', #{courierName}, '%')


    AND is_qualified = #{isQualified}


    AND waybill_no LIKE CONCAT('%', #{waybillNo}, '%')


    AND fake_sign_type = #{fakeSignType}

ORDER BY data_date DESC, report_time DESC
